function defaultLinkType(){const t=getUrlVars(window.location.href).a||localStorage.linktype||"link",e=document.querySelector(`.link-type li[data-label="${t}"]`),a=document.querySelector(".link-type input");e.classList.add("active"),a.value=t}function defaultSecurity(){const t=localStorage.security||"base64",e=document.querySelector('dropmenu[data-type="security"]'),a=e.querySelector("input"),n=e.querySelector(`li[data-option="${t}"]`);e.querySelector(".value").textContent=n.textContent,a.value=t,n.classList.add("active")}function defaultShortening(){const t=localStorage.shortening||"is.gd",e=document.querySelector('dropmenu[data-type="shortening"]'),a=e.querySelector("input"),n=e.querySelector(`li[data-option="${t}"]`);e.querySelector(".value").textContent=n.textContent,a.value=t,n.classList.add("active")}function setDefaults(){try{defaultLinkType()}catch{}try{defaultSecurity()}catch{}try{defaultShortening()}catch{}}setDefaults();